#include <stdio.h>
#include <stdlib.h>

int cmp(const void *a, const void *b) {
    return (*(int*)a) - (*(int*)b);
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; long long W, Wr; scanf("%d %lld %lld", &N, &W, &Wr);
        int *arr = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &arr[i]);
        qsort(arr, N, sizeof(int), cmp);
        long long extra = 0;
        for (int i = 0; i < N;) {
            int j = i;
            while (j < N && arr[j] == arr[i]) ++j;
            int cnt = j - i;
            long long pairs = cnt / 2;
            extra += pairs * 2LL * arr[i];
            i = j;
        }
        free(arr);
        if (Wr >= W || Wr + extra >= W) printf("YES\n");
        else printf("NO\n");
    }
    return 0;
}

