import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); W = int(next(it)); Wr = int(next(it))
        freq = {}
        for _ in range(N):
            w = int(next(it))
            freq[w] = freq.get(w, 0) + 1
        extra = 0
        for v, c in freq.items():
            pairs = c // 2
            extra += pairs * 2 * v
        if Wr >= W or Wr + extra >= W:
            out_lines.append("YES")
        else:
            out_lines.append("NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

